import React, { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import {
  Box,
  Container,
  Typography,
  Button,
  Paper,
  Grid,
  Card,
  CardContent,
  Divider,
  CircularProgress,
  Alert,
  Fade,
  Avatar,
  Chip,
  IconButton
} from '@mui/material';
import CheckCircleIcon from '@mui/icons-material/CheckCircle';
import CancelIcon from '@mui/icons-material/Cancel';
import VerifiedUserIcon from '@mui/icons-material/VerifiedUser';
import FormatQuoteIcon from '@mui/icons-material/FormatQuote';
import { useTheme } from '@mui/material/styles';
import TwitterIcon from '@mui/icons-material/Twitter';
import FacebookIcon from '@mui/icons-material/Facebook';
import LinkedInIcon from '@mui/icons-material/LinkedIn';

const VerifyPage = () => {
  const { id } = useParams();
  const theme = useTheme();
  const [testimonial, setTestimonial] = useState(null);
  const [loading, setLoading] = useState(true);
  const [isVerified, setIsVerified] = useState(false);

  useEffect(() => {
    // Simulate API call to fetch testimonial
    setTimeout(() => {
      setTestimonial({
        id,
        clientName: 'Michael Thompson',
        clientEmail: 'michael@example.com',
        clientTitle: 'Marketing Director',
        clientCompany: 'Acme Inc.',
        original: 'The coaching was good. I learned some things that helped me.',
        enhanced: 'Working with this coach transformed how I approach challenges. I went from feeling stuck to landing two major clients in just 3 weeks. The coaching didnt just teach me tactics—it changed my entire mindset about whats possible.',
        status: 'pending',
        date: '2023-05-15'
      });
      setLoading(false);
    }, 1000);
  }, [id]);

  const handleVerify = () => {
    setLoading(true);

    // Simulate API call to verify testimonial
    setTimeout(() => {
      setIsVerified(true);
      setLoading(false);
    }, 1000);
  };

  if (loading && !testimonial) {
    return (
      <Container maxWidth="md" sx={{ py: 10, textAlign: 'center' }}>
        <CircularProgress />
        <Typography variant="body1" sx={{ mt: 2 }}>
          Loading testimonial...
        </Typography>
      </Container>
    );
  }

  if (isVerified) {
    return (
      <Container maxWidth="md" sx={{ py: 10 }}>
        <Fade in={isVerified}>
          <Box sx={{ mt: 6, textAlign: 'center' }}>
            <Box 
              sx={{ 
                width: 80, 
                height: 80, 
                borderRadius: '50%', 
                bgcolor: 'success.light',
                color: 'success.main',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                mx: 'auto',
                mb: 3
              }}
            >
              <CheckCircleIcon sx={{ fontSize: 40 }} />
            </Box>

            <Typography variant="h4" gutterBottom>
              Thank You for Verifying Your Testimonial!
            </Typography>

            <Typography variant="body1" color="text.secondary" sx={{ mb: 4, maxWidth: 500, mx: 'auto' }}>
              Your testimonial has been verified and will help others make informed decisions. 
              We appreciate your honest feedback.
            </Typography>

            <Box 
              sx={{ 
                p: 3, 
                bgcolor: 'primary.light', 
                borderRadius: 2,
                maxWidth: 500,
                mx: 'auto',
                mb: 4
              }}
            >
              <Typography variant="subtitle2" color="primary.dark" gutterBottom>
                SHARE YOUR EXPERIENCE
              </Typography>
              <Typography variant="body2" color="text.secondary">
                Would you like to share your testimonial on social media? It can help others 
                who might benefit from the same service.
              </Typography>

              <Box sx={{ display: 'flex', justifyContent: 'center', gap: 2, mt: 3 }}>
                <IconButton sx={{ color: '#1DA1F2' }}>
                  <TwitterIcon />
                </IconButton>
                <IconButton sx={{ color: '#4267B2' }}>
                  <FacebookIcon />
                </IconButton>
                <IconButton sx={{ color: '#0077B5' }}>
                  <LinkedInIcon />
                </IconButton>
              </Box>
            </Box>

            <Typography variant="body2" color="text.secondary">
              You can close this window now. Thank you again for your time!
            </Typography>
          </Box>
        </Fade>
      </Container>
    );
  }

  return (
    <Container maxWidth="md" sx={{ py: 10 }}>
      <Fade in={true}>
        <Box>
          <Typography variant="h4" align="center" gutterBottom>
            Verify Your Testimonial
          </Typography>
          <Typography variant="body1" align="center" color="text.secondary" sx={{ mb: 6 }}>
            Please review the enhanced version of your testimonial and approve it if it accurately represents your experience.
          </Typography>

          <Box sx={{ mb: 6 }}>
            <Card 
              elevation={0}
              sx={{ 
                mb: 4, 
                borderRadius: 3,
                boxShadow: '0 4px 20px rgba(0,0,0,0.08)'
              }}
            >
              <CardContent sx={{ p: 4 }}>
                <Typography variant="h6" gutterBottom>
                  Original Testimonial
                </Typography>
                <Typography variant="body1" sx={{ mb: 4, color: 'text.secondary' }}>
                  "{testimonial.original}"
                </Typography>

                <Divider sx={{ my: 3 }} />

                <Typography variant="h6" gutterBottom>
                  Enhanced Testimonial
                </Typography>
                <Box sx={{ position: 'relative' }}>
                  <FormatQuoteIcon 
                    sx={{ 
                      position: 'absolute',
                      top: -10,
                      left: -5,
                      color: theme.palette.primary.main,
                      opacity: 0.2,
                      fontSize: 40,
                      transform: 'rotate(180deg)'
                    }}
                  />
                  <Typography variant="body1" sx={{ pl: 4 }}>
                    "{testimonial.enhanced}"
                  </Typography>
                </Box>
              </CardContent>
            </Card>

            <Alert severity="info" sx={{ mb: 4 }}>
              By approving this testimonial, you confirm that it accurately represents your experience and give permission for it to be used for promotional purposes.
            </Alert>

            <Box sx={{ display: 'flex', justifyContent: 'center', gap: 3 }}>
              <Button 
                variant="contained" 
                color="primary"
                size="large"
                onClick={handleVerify}
                startIcon={<CheckCircleIcon />}
                sx={{ px: 4 }}
              >
                Yes, I approve this testimonial
              </Button>

              <Button 
                variant="outlined"
                color="error"
                size="large"
                startIcon={<CancelIcon />}
              >
                No, this needs changes
              </Button>
            </Box>
          </Box>
        </Box>
      </Fade>
    </Container>
  );
};

export default VerifyPage;
